import { useState, useEffect } from 'react';
import { db } from '../db';
import { X, UserPlus, Edit } from 'lucide-react';

function AddCustomerModal({ isOpen, onClose, customerToEdit }) {
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    email: '',
    sport: 'Tennis'
  });

  useEffect(() => {
    if (customerToEdit) {
      setFormData({
        name: customerToEdit.name,
        phone: customerToEdit.phone,
        email: customerToEdit.email,
        sport: customerToEdit.sport
      });
    } else {
      setFormData({ name: '', phone: '', email: '', sport: 'Tennis' });
    }
  }, [customerToEdit, isOpen]);

  if (!isOpen) return null;

  const handleSave = async (e) => {
    e.preventDefault();
    if (customerToEdit) {
      await db.customers.update(customerToEdit.id, { ...formData });
    } else {
      await db.customers.add({ ...formData });
    }
    onClose();
  };

  return (
    <div className="modal-overlay animate-fade-in">
      <div className="modal-container glass-panel" style={{ maxWidth: '400px' }}>
        <header className="modal-header">
          <h2>
            {customerToEdit ? <Edit size={20} style={{ display: 'inline', marginRight: '8px' }}/> : <UserPlus size={20} style={{ display: 'inline', marginRight: '8px' }}/>}
            {customerToEdit ? 'Edit Customer' : 'Add Customer'}
          </h2>
          <button className="btn-icon" onClick={onClose} type="button"><X size={20} /></button>
        </header>

        <form onSubmit={handleSave}>
          <div className="modal-body">
            <div className="form-group">
              <label>Full Name</label>
              <input 
                type="text" 
                required
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
              />
            </div>
            <div className="form-group">
              <label>Phone Number (WhatsApp)</label>
              <input 
                type="tel" 
                required
                value={formData.phone}
                onChange={e => setFormData({...formData, phone: e.target.value})}
              />
            </div>
            <div className="form-group">
              <label>Email Address</label>
              <input 
                type="email" 
                value={formData.email}
                onChange={e => setFormData({...formData, email: e.target.value})}
              />
            </div>
            <div className="form-group">
              <label>Primary Sport</label>
              <select 
                value={formData.sport}
                onChange={e => setFormData({...formData, sport: e.target.value})}
              >
                <option value="Tennis">Tennis</option>
                <option value="Badminton">Badminton</option>
              </select>
            </div>
          </div>

          <footer className="modal-footer" style={{ justifyContent: 'flex-end', gap: '1rem' }}>
            <button className="btn-secondary" onClick={onClose} type="button">Cancel</button>
            <button className="btn-primary" type="submit">Save Customer</button>
          </footer>
        </form>
      </div>
    </div>
  );
}

export default AddCustomerModal;

import { useState } from 'react';
import { useUI } from '../context/UIContext';
import { db } from '../db';
import { X, Play, Square, Plus } from 'lucide-react';
import './NewJobModal.css';

function NewJobModal() {
  const { isJobModalOpen, setJobModalOpen } = useUI();
  const [timerRunning, setTimerRunning] = useState(false);
  const [timerSeconds, setTimerSeconds] = useState(0);

  const [formData, setFormData] = useState({
    customerName: '',
    racketModel: '',
    sport: 'Tennis',
    mainsTension: '',
    crossesTension: '',
    preStretch: '0',
    knots: '2',
    notes: '',
    addons: []
  });

  if (!isJobModalOpen) return null;

  const handleClose = () => setJobModalOpen(false);

  const toggleAddon = (addon) => {
    setFormData(prev => ({
      ...prev,
      addons: prev.addons.includes(addon) 
        ? prev.addons.filter(a => a !== addon) 
        : [...prev.addons, addon]
    }));
  };

  const handleSave = async () => {
    await db.jobs.add({
      customerName: formData.customerName || 'Walk-in Customer',
      racketModel: formData.racketModel || 'Unknown Racket',
      sport: formData.sport,
      mainsTension: formData.mainsTension,
      crossesTension: formData.crossesTension,
      addons: formData.addons,
      notes: formData.notes,
      status: 'Pending', // Pending, Ready, Paid
      createdAt: new Date().toISOString()
    });
    // In real app, we'd handle "Save & Add Another" vs "Save & Close"
    setJobModalOpen(false);
  };

  return (
    <div className="modal-overlay animate-fade-in">
      <div className="modal-container glass-panel">
        <header className="modal-header">
          <h2>New Job Entry</h2>
          <button className="btn-icon" onClick={handleClose}><X size={20} /></button>
        </header>

        <div className="modal-body">
          <div className="form-group">
            <label>Customer Name</label>
            <input 
              type="text" 
              placeholder="Start typing customer name..." 
              value={formData.customerName}
              onChange={(e) => setFormData({...formData, customerName: e.target.value})}
            />
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Racket Model</label>
              <input 
                type="text" 
                placeholder="e.g. Wilson Pro Staff" 
                value={formData.racketModel}
                onChange={(e) => setFormData({...formData, racketModel: e.target.value})}
              />
            </div>
            <div className="form-group">
              <label>Sport</label>
              <select value={formData.sport} onChange={(e) => setFormData({...formData, sport: e.target.value})}>
                <option value="Tennis">Tennis ≡ƒÄ╛</option>
                <option value="Badminton">Badminton ≡ƒÅ╕</option>
              </select>
            </div>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label>Mains Tension (lbs)</label>
              <input 
                type="number" 
                placeholder="55" 
                value={formData.mainsTension}
                onChange={(e) => setFormData({...formData, mainsTension: e.target.value})}
              />
            </div>
            <div className="form-group">
              <label>Crosses Tension (lbs)</label>
              <input 
                type="number" 
                placeholder="53" 
                value={formData.crossesTension}
                onChange={(e) => setFormData({...formData, crossesTension: e.target.value})}
              />
            </div>
          </div>

          <div className="form-group addons-group">
            <label>Add-ons</label>
            <div className="addons-list">
              {['Overgrip', 'Stencil', 'Vibration Dampener', 'Head Guard Tape'].map(addon => (
                <button 
                  key={addon}
                  className={`addon-chip ${formData.addons.includes(addon) ? 'active' : ''}`}
                  onClick={() => toggleAddon(addon)}
                >
                  {addon}
                </button>
              ))}
            </div>
          </div>
        </div>

        <footer className="modal-footer">
          <div className="timer-controls">
            <button className="btn-icon" onClick={() => setTimerRunning(!timerRunning)}>
              {timerRunning ? <Square size={20} color="#ef4444" /> : <Play size={20} color="#10b981" />}
            </button>
            <span>{timerSeconds}s</span>
          </div>
          <div className="action-buttons">
            <button className="btn-secondary" onClick={handleClose}>Cancel</button>
            <button className="btn-primary" onClick={handleSave}>Save Job</button>
          </div>
        </footer>
      </div>
    </div>
  );
}

export default NewJobModal;

import { createContext, useContext, useState } from 'react';

const UIContext = createContext();

export function UIProvider({ children }) {
  const [isJobModalOpen, setJobModalOpen] = useState(false);

  return (
    <UIContext.Provider value={{ isJobModalOpen, setJobModalOpen }}>
      {children}
    </UIContext.Provider>
  );
}

export const useUI = () => useContext(UIContext);

import { useState } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../db';
import { Search, MessageCircle, UserPlus, Phone, Edit, Trash } from 'lucide-react';
import AddCustomerModal from '../components/AddCustomerModal';
import './Customers.css';

function Customers() {
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [customerToEdit, setCustomerToEdit] = useState(null);
  const customers = useLiveQuery(() => db.customers.toArray()) || [];

  const filteredCustomers = customers.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleAddDummyCustomer = async () => {
    await db.customers.add({
      name: 'Roger Federer',
      phone: '+1 123-456-7890',
      email: 'roger@tennis.com',
      sport: 'Tennis'
    });
    await db.customers.add({
      name: 'Lin Dan',
      phone: '+1 987-654-3210',
      email: 'lindan@badminton.com',
      sport: 'Badminton'
    });
  };

  const openCreateModal = () => {
    setCustomerToEdit(null);
    setIsModalOpen(true);
  };

  const openEditModal = (c) => {
    setCustomerToEdit(c);
    setIsModalOpen(true);
  };

  return (
    <div className="page-container animate-fade-in">
      <header className="page-header">
        <h1>Customers</h1>
        <p className="text-muted">Manage your tennis and badminton clients.</p>
      </header>

      <div className="glass-panel customer-toolbar">
        <div className="search-bar">
          <Search size={18} className="text-muted" />
          <input 
            type="text" 
            placeholder="Search by name..." 
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <button className="btn-primary" onClick={openCreateModal}>
          <UserPlus size={18} /> Add Customer
        </button>
      </div>

      <div className="glass-panel main-table-container">
        {filteredCustomers.length === 0 ? (
          <div className="empty-state">
            <p className="text-muted">No customers found. Try adding some.</p>
          </div>
        ) : (
          <table className="data-table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Sport</th>
                <th>Contact</th>
                <th>Reach Out</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredCustomers.map(customer => (
                <tr key={customer.id}>
                  <td className="fw-600">{customer.name}</td>
                  <td>
                    <span className={`badge ${customer.sport === 'Tennis' ? 'badge-tennis' : 'badge-badminton'}`}>
                      {customer.sport}
                    </span>
                  </td>
                  <td>
                    <div className="contact-info">
                      <span className="text-muted"><Phone size={14} /> {customer.phone}</span>
                    </div>
                  </td>
                  <td>
                    <a className="btn-link" href={`https://wa.me/${customer.phone?.replace(/[^0-9]/g, '')}`} target="_blank" rel="noreferrer">
                      <MessageCircle size={18} color="#10b981" /> WhatsApp
                    </a>
                  </td>
                  <td>
                    <div style={{ display: 'flex', gap: '0.5rem' }}>
                      <button className="btn-icon" onClick={() => openEditModal(customer)} title="Edit Customer">
                        <Edit size={16} />
                      </button>
                      <button className="btn-icon" onClick={async () => await db.customers.delete(customer.id)} title="Delete Customer">
                        <Trash size={16} color="#ef4444" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <AddCustomerModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        customerToEdit={customerToEdit}
      />
    </div>
  );
}

export default Customers;

import { useState } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../db';
import { PlusCircle, AlertTriangle } from 'lucide-react';
import AddReelModal from '../components/AddReelModal';
import './Inventory.css';

function Inventory() {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const inventory = useLiveQuery(() => db.inventory.toArray()) || [];

  const handleAddDummyReel = async () => {
    await db.inventory.add({
      brand: 'Luxilon',
      model: 'ALU Power',
      gauge: '1.25',
      color: 'Silver',
      lengthMeters: 200,
      costPrice: 220
    });
    // Low stock example
    await db.inventory.add({
      brand: 'Yonex',
      model: 'BG80',
      gauge: '0.68',
      color: 'Yellow',
      lengthMeters: 8, // Low stock, since < 10m is insufficient for Badminton
      costPrice: 150
    });
  };

  return (
    <div className="page-container animate-fade-in">
      <header className="page-header">
        <h1>String Inventory</h1>
        <p className="text-muted">Manage your reels and tracking.</p>
      </header>

      <div className="glass-panel inventory-toolbar">
        <button className="btn-primary" onClick={() => setIsModalOpen(true)}>
          <PlusCircle size={18} /> Add New Reel
        </button>
      </div>

      <div className="glass-panel main-table-container">
        {inventory.length === 0 ? (
          <div className="empty-state">
            <p className="text-muted">No inventory found. Add a reel to start tracking stock.</p>
          </div>
        ) : (
          <table className="data-table">
            <thead>
              <tr>
                <th>Brand / Model</th>
                <th>Specs</th>
                <th>Stock (Meters)</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {inventory.map(reel => {
                const isLowStock = reel.lengthMeters < 12; // Generic threshold
                return (
                  <tr key={reel.id}>
                    <td>
                      <div className="reel-info">
                        <strong>{reel.brand}</strong>
                        <span className="text-muted">{reel.model}</span>
                      </div>
                    </td>
                    <td>
                      <span className="badge badge-specs">{reel.gauge}mm ΓÇó {reel.color}</span>
                    </td>
                    <td>
                      <div className={`stock-meter ${isLowStock ? 'low-stock' : ''}`}>
                        <div className="stock-fill" style={{ width: `${Math.min(100, (reel.lengthMeters / 200) * 100)}%`, background: isLowStock ? '#ef4444' : '#10b981' }}></div>
                        <span>{reel.lengthMeters}m</span>
                      </div>
                    </td>
                    <td>
                      {isLowStock ? (
                        <span className="badge badge-danger"><AlertTriangle size={12} /> Low Stock</span>
                      ) : (
                        <span className="badge badge-ready">In Stock</span>
                      )}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>

      <AddReelModal 
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
      />
    </div>
  );
}

export default Inventory;
